"use client";

import { useEffect, useState } from "react";
import Cookies from "js-cookie";
import { useRouter } from "next/navigation";
import contenido from "../../../../public/contenido.json";

export default function NavbarAdmin() {
  const [tokenExists, setTokenExists] = useState(false);
  const router = useRouter();

  useEffect(() => {
    const token = Cookies.get("token");
    if (token) setTokenExists(true);
  }, []);

  if (!tokenExists) return null;

  // Secciones que son arreglos en el JSON (ej. productos, servicios...)
  const sections = (Object.keys(contenido) as Array<keyof typeof contenido>)
    .filter((key) => Array.isArray((contenido as any)[key]))
    .map((key) => ({
      nombre: key.charAt(0).toUpperCase() + key.slice(1), // Ej. productos -> Productos
      href: `/dashboard#${key}`
    }));

  const handleLogout = () => {
    router.push("/logout");
  };

  return (
    <div className="flex flex-col h-screen justify-between bg-white dark:bg-gray-900 p-4 border-r dark:border-gray-700">
      <div>
        <h2 className="text-xl font-bold mb-4 text-blue-600 dark:text-blue-400">Panel Admin</h2>
        <nav className="space-y-2">
          {sections.map((link, i) => (
            <a
              key={i}
              href={link.href}
              className="block text-sm text-gray-700 dark:text-gray-200 hover:text-blue-600 dark:hover:text-blue-400"
            >
              {link.nombre}
            </a>
          ))}
        </nav>
      </div>
      <button
        onClick={handleLogout}
        className="mt-4 text-sm text-red-600 dark:text-red-400 hover:underline"
      >
        Cerrar sesión
      </button>
    </div>
  );
}
